mapper.insert:
		/*
             SQL ID : QstnDAO.qstnRegist
             설  명 : 문항등록
         */
         INSERT INTO TB_LMS_QSTN (
         	  QSTN_ID
			, EXAM_DTL_ID
			, QSTN_TTL
			, QSTN_CTS
			, QSTN_SEQNO
			, QSTN_CNDDT_SEQNO
			, QSTN_GBNCD
			, QSTN_RSPNS_TYCD
			, QSTN_SCR
			, QSTN_DFCTLV_TYCD
			, CRANS_TYCD
			, RGTR_ID
			, REG_DTTM
         ) VALUES (
         	  #{qstnId}
         	, #{examDtlId}
			, #{qstnTtl}
			, #{qstnCts}
			, #{qstnSeqno}
			, #{qstnCnddtSeqno}
			, #{qstnGbncd}
			, #{qstnRspnsTycd}
			, #{qstnScr}
			, #{qstnDfctlvTycd}
			, #{cransTycd}
			, #{rgtrId}
			, FN_DTTM()
         )

mapper.update:
		/*
             SQL ID : QstnDAO.qstnModify
             설  명 : 문항수정
         */
         UPDATE TB_LMS_QSTN SET
          	  MDFR_ID   = #{mdfrId}
    		, MOD_DTTM = FN_DTTM()
    		, CRANS_TYCD = #{cransTycd}

    		, QSTN_TTL = #{qstnTtl}


    		, QSTN_CTS = #{qstnCts}


    		, QSTN_RSPNS_TYCD = #{qstnRspnsTycd}


    		, QSTN_DFCTLV_TYCD = #{qstnDfctlvTycd}

    	  WHERE QSTN_ID = #{qstnId}
    	    AND EXAM_DTL_ID = #{examDtlId}

mapper.select:
		/*
             SQL ID : QstnDAO.qstnSelect
             설  명 : 문항조회
         */
         SELECT
         	*
           FROM TB_LMS_QSTN
          WHERE QSTN_ID = #{qstnId}
            AND EXAM_DTL_ID = #{examDtlId}

mapper.update:
		/*
             SQL ID : QstnDAO.qstnDelynModify
             설  명 : 문항삭제여부수정
         */
		UPDATE TB_LMS_QSTN SET
			  MDFR_ID = #{mdfrId}
			, MOD_DTTM = FN_DTTM()
			, DELYN = 'Y'
		 WHERE EXAM_DTL_ID = #{examDtlId}
		   AND QSTN_SEQNO = #{qstnSeqno}

		   AND QSTN_CNDDT_SEQNO = #{qstnCnddtSeqno}

/* SQL ID : QstnDAO.qstnDelNSeqnoModify 설 명 : 문항미삭제순번수정 */ MERGE INTO TB_LMS_QSTN QSTN USING ( SELECT EXAM_DTL_ID , QSTN_SEQNO , (SELECT COUNT(*) FROM TB_LMS_QSTN WHERE EXAM_DTL_ID = #{examDtlId} AND DELYN = 'N' AND QSTN_SEQNO = #{qstnSeqno}) AS QSTN_CNT FROM TB_LMS_QSTN WHERE EXAM_DTL_ID = #{examDtlId} AND QSTN_SEQNO = #{qstnSeqno} AND QSTN_CNDDT_SEQNO = 1 AND ROWNUM = 1 ORDER BY QSTN_SEQNO, QSTN_CNDDT_SEQNO ) DEL_N_QSTN ON ( QSTN.EXAM_DTL_ID = DEL_N_QSTN.EXAM_DTL_ID AND QSTN.DELYN = 'N' ) WHEN MATCHED THEN UPDATE SET QSTN.MDFR_ID = #{mdfrId} , QSTN.MOD_DTTM = FN_DTTM()
, QSTN.QSTN_SEQNO = CASE WHEN DEL_N_QSTN.QSTN_CNT > 0 THEN QSTN.QSTN_SEQNO WHEN QSTN.QSTN_SEQNO > #{qstnSeqno} THEN QSTN.QSTN_SEQNO - 1 ELSE QSTN.QSTN_SEQNO END , QSTN.QSTN_CNDDT_SEQNO = CASE WHEN DEL_N_QSTN.QSTN_CNT > 0 AND DEL_N_QSTN.QSTN_SEQNO = #{qstnSeqno} AND QSTN.QSTN_CNDDT_SEQNO > #{qstnCnddtSeqno} THEN QSTN.QSTN_CNDDT_SEQNO - 1 ELSE QSTN.QSTN_CNDDT_SEQNO END
, QSTN.QSTN_SEQNO = QSTN.QSTN_SEQNO - 1

		/*
             SQL ID : QstnDAO.quizQstnScrModify
             설  명 : 퀴즈문항점수수정
         */
         UPDATE TB_LMS_QSTN SET
         	  MDFR_ID = #{mdfrId}
         	, MOD_DTTM = FN_DTTM()
         	, QSTN_SCR = #{qstnScr}
          WHERE EXAM_DTL_ID = #{examDtlId}
            AND QSTN_SEQNO = #{qstnSeqno}

		/*
             SQL ID : QstnDAO.cmptnYQuizQstnScrBulkModify
             설  명 : 출제완료퀴즈문항점수일괄수정
         */

         UPDATE TB_LMS_QSTN SET
         	  MDFR_ID = #{item.mdfrId}
         	, MOD_DTTM = FN_DTTM()
         	, QSTN_SCR = #{item.qstnScr}
          WHERE EXAM_DTL_ID = #{item.examDtlId}
            AND DELYN = 'N'
            AND QSTN_SEQNO = #{item.qstnSeqno}

mapper.insert:
/* SQL ID : QbnkQstnDAO.quizQstnCopy 설 명 : 퀴즈문항가져오기 */ INSERT INTO TB_LMS_QSTN ( QSTN_ID , EXAM_DTL_ID , QSTN_TTL , QSTN_CTS , QSTN_RSPNS_TYCD , QSTN_DFCTLV_TYCD , CRANS_TYCD , QSTN_SEQNO , RGTR_ID , REG_DTTM , QSTN_CNDDT_SEQNO ) SELECT A.* , ROW_NUMBER() OVER(ORDER BY QSTN_TTL) AS QSTN_CNDDT_SEQNO FROM (
SELECT #{item.qstnId} AS QSTN_ID , #{item.examDtlId} AS EXAM_DTL_ID , COALESCE(Q.QSTN_TTL, B.QSTN_TTL) AS QSTN_TTL , COALESCE(Q.QSTN_CTS, B.QSTN_CTS) AS QSTN_CTS , COALESCE(Q.QSTN_RSPNS_TYCD, B.QSTN_RSPNS_TYCD) AS QSTN_RSPNS_TYCD , COALESCE(Q.QSTN_DFCTLV_TYCD, B.QSTN_DFCTLV_TYCD) AS QSTN_DFCTLV_TYCD , COALESCE(Q.CRANS_TYCD, B.CRANS_TYCD) AS CRANS_TYCD , (SELECT NVL(MAX(QSTN_SEQNO), 0) + 1 FROM TB_LMS_QSTN WHERE EXAM_DTL_ID = #{item.examDtlId} AND DELYN = 'N') AS QSTN_SEQNO , #{item.rgtrId} AS RGTR_ID , FN_DTTM() AS REG_DTTM FROM DUAL LEFT JOIN TB_LMS_QSTN Q ON Q.QSTN_ID = #{item.copyQstnId} LEFT JOIN TB_LMS_QBNK_QSTN B ON B.QBNK_QSTN_ID = #{item.copyQstnId}
) A
